module freq_divider(
  input clk,
  input rst_n,
  output reg clk_out
);

  reg [1:0] count_reg;

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      count_reg <= 2'b00;
      clk_out <= 1'b0;
    end else begin
      if (count_reg == 2'b11) begin
        count_reg <= 2'b00;
        clk_out <= ~clk_out;
      end else begin
        count_reg <= count_reg + 1;
      end
    end
  end

endmodule
